@startuml
package Actor {
    class MutableSequence {
        +_getitem__
        +_setitem__
        +_delitem__
        +_len__
        +insert
        +_contains__
        +iter__
        +_reversed__
        +index
        +count
        +append
        +reverse
        +extend
        +pop
        +remove
        +_iadd__
    }
}

package Interface {
    class Iterable {
        +_iter__
    }
}

    class Reversible {
        +_reversed__
    }

    class Sized {
        +_len__
    }

    class Container {
        +_contains__
    }

    class Collection {
        +_contains__
        +_iter__
        +_len__
    }

    class Sequence {
        +_getitem__
        +_len__
        +_contains__
        +_iter__
        +_reversed__
        +index
        +count
    }

    MutableSequence ..> Iterable : inherits
    MutableSequence ..> Reversible : inherits
    MutableSequence ..> Sized : inherits
    MutableSequence ..> Container : inherits
    MutableSequence ..> Collection : inherits
    MutableSequence ..> Sequence : inherits

@enduml
